CREATE TABLE IF NOT EXISTS "KnowledgeChangeProposal" ("id" TEXT PRIMARY KEY,"organizationId" TEXT,"type" TEXT NOT NULL,"targetCode" TEXT NOT NULL,"payloadJson" JSONB NOT NULL,"reason" TEXT NOT NULL,"proposedBy" TEXT NOT NULL,"status" TEXT NOT NULL DEFAULT 'PROPOSED',"reviewsJson" JSONB,"createdAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP,"updatedAt" TIMESTAMP(3) NOT NULL);
CREATE TABLE IF NOT EXISTS "GovernedReferenceSet" ("id" TEXT PRIMARY KEY,"organizationId" TEXT,"testCode" TEXT NOT NULL,"unit" TEXT NOT NULL,"lower" DOUBLE PRECISION NOT NULL,"upper" DOUBLE PRECISION NOT NULL,"contextJson" JSONB NOT NULL,"version" TEXT NOT NULL,"reviewStatus" TEXT NOT NULL DEFAULT 'DRAFT',"sourceCitation" TEXT,"approvedBy" TEXT,"effectiveFrom" TIMESTAMP(3),"effectiveTo" TIMESTAMP(3),"createdAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP,"updatedAt" TIMESTAMP(3) NOT NULL);
CREATE TABLE IF NOT EXISTS "CriticalValuePolicy" ("id" TEXT PRIMARY KEY,"organizationId" TEXT,"testCode" TEXT NOT NULL,"unit" TEXT NOT NULL,"low" DOUBLE PRECISION,"high" DOUBLE PRECISION,"severity" TEXT NOT NULL DEFAULT 'CRITICAL',"active" BOOLEAN NOT NULL DEFAULT true,"version" TEXT NOT NULL,"approvedBy" TEXT,"createdAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP,"updatedAt" TIMESTAMP(3) NOT NULL);
